import{_ as a,o as t,c as l,ag as e}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"🗺️ 앞으로의 여정","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/5-다음단계.md","filePath":"학습자료/5-다음단계.md"}'),r={name:"학습자료/5-다음단계.md"};function i(u,o,d,s,c,n){return t(),l("div",null,[...o[0]||(o[0]=[e('<h1 id="🗺️-앞으로의-여정" tabindex="-1">🗺️ 앞으로의 여정 <a class="header-anchor" href="#🗺️-앞으로의-여정" aria-label="Permalink to &quot;🗺️ 앞으로의 여정&quot;">​</a></h1><blockquote><p>세미나를 마치셨습니다. 수고하셨어요! 오늘이 끝이 아니라, 오늘이 <strong>진짜 시작</strong>입니다.</p></blockquote><hr><h2 id="오늘-해낸-것들-✅" tabindex="-1">오늘 해낸 것들 ✅ <a class="header-anchor" href="#오늘-해낸-것들-✅" aria-label="Permalink to &quot;오늘 해낸 것들 ✅&quot;">​</a></h2><ol><li>✅ Claude Code가 뭔지 알게 됐다</li><li>✅ 스킬, CLAUDE.md, MCP 핵심 개념을 이해했다</li><li>✅ 이메일초안 스킬을 직접 만들어봤다</li><li>✅ 나만의 스킬 설계서를 작성했다</li></ol><div class="tip custom-block"><p class="custom-block-title">작은 것 같아 보여도 정말 큰 첫 걸음입니다</p><p>개념을 &quot;아는 것&quot;과 직접 &quot;해본 것&quot;은 완전히 다릅니다. 오늘 직접 손으로 만들어본 그 경험이 앞으로의 모든 것을 가능하게 합니다.</p></div><hr><h2 id="로드맵-이렇게-성장해가세요" tabindex="-1">로드맵: 이렇게 성장해가세요 <a class="header-anchor" href="#로드맵-이렇게-성장해가세요" aria-label="Permalink to &quot;로드맵: 이렇게 성장해가세요&quot;">​</a></h2><p>세미나 직후보다 <strong>1-2일 안에</strong> 시작하는 게 가장 효과적입니다. 기억이 생생할 때 바로 써보세요.</p><hr><h3 id="📅-이번-주-—-1단계-오늘-만든-스킬-써보기" tabindex="-1">📅 이번 주 — 1단계: 오늘 만든 스킬 써보기 <a class="header-anchor" href="#📅-이번-주-—-1단계-오늘-만든-스킬-써보기" aria-label="Permalink to &quot;📅 이번 주 — 1단계: 오늘 만든 스킬 써보기&quot;">​</a></h3><ul><li>이메일초안 스킬을 실제 업무에서 사용해보세요</li><li>결과가 마음에 안 들면 SKILL.md를 직접 수정해보세요</li><li>&quot;이 부분이 아쉽다&quot; 싶은 게 생기면 → 그게 다음 개선 포인트입니다</li></ul><p><strong>이걸 하면 이런 변화가!</strong></p><blockquote><p>매일 쓰던 이메일 한 통에 걸리던 10분이 2분으로 줄어듭니다. &quot;어, 이게 진짜 된다&quot; 는 감각이 생깁니다. 그게 핵심입니다.</p></blockquote><div class="info custom-block"><p class="custom-block-title">잘 안 되는 게 정상입니다</p><p>처음에는 결과가 기대와 다를 수 있어요. 그럴 때는 SKILL.md에 더 구체적인 규칙을 추가해보세요. 반복할수록 좋아집니다. 처음부터 완벽할 필요 없어요.</p></div><hr><h3 id="📅-다음-주-—-2단계-설계서-→-실제-스킬-만들기" tabindex="-1">📅 다음 주 — 2단계: 설계서 → 실제 스킬 만들기 <a class="header-anchor" href="#📅-다음-주-—-2단계-설계서-→-실제-스킬-만들기" aria-label="Permalink to &quot;📅 다음 주 — 2단계: 설계서 → 실제 스킬 만들기&quot;">​</a></h3><ul><li>오늘 작성한 설계서를 SKILL.md로 변환하세요</li><li>Claude Code에게 &quot;이 설계서 보고 SKILL.md 만들어줘&quot;라고 하면 됩니다</li><li>테스트 → 결과 확인 → 수정 → 반복</li></ul><p><strong>이걸 하면 이런 변화가!</strong></p><blockquote><p>나만의 두 번째 스킬이 생깁니다. &quot;내가 AI를 커스터마이징 했다&quot; 는 뿌듯함을 느끼게 됩니다.</p></blockquote><hr><h3 id="📅-2주-후-—-3단계-claude-md-작성하기" tabindex="-1">📅 2주 후 — 3단계: CLAUDE.md 작성하기 <a class="header-anchor" href="#📅-2주-후-—-3단계-claude-md-작성하기" aria-label="Permalink to &quot;📅 2주 후 — 3단계: CLAUDE.md 작성하기&quot;">​</a></h3><ul><li>자주 쓰는 프로젝트 폴더에 CLAUDE.md 파일을 만들어보세요</li><li>내 작업 스타일, 선호하는 형식, 자주 쓰는 용어 등을 적어두면 됩니다</li><li>Claude Code가 매번 물어보지 않아도 맥락을 알고 시작합니다</li></ul><p><strong>이걸 하면 이런 변화가!</strong></p><blockquote><p>Claude Code가 &quot;저 뭐 할까요?&quot; 가 아니라 &quot;이렇게 하면 될까요?&quot; 로 바뀝니다. AI가 나를 아는 느낌. 함께 일하는 파트너가 됩니다.</p></blockquote><hr><h3 id="📅-한-달-후-—-4단계-mcp-하나-연결해보기" tabindex="-1">📅 한 달 후 — 4단계: MCP 하나 연결해보기 <a class="header-anchor" href="#📅-한-달-후-—-4단계-mcp-하나-연결해보기" aria-label="Permalink to &quot;📅 한 달 후 — 4단계: MCP 하나 연결해보기&quot;">​</a></h3><ul><li><strong>Google Calendar MCP</strong> 연결을 추천합니다 (가장 쉽고 실용적)</li><li>연결하면 &quot;내일 오전 10시 팀 미팅 잡아줘&quot; 같은 게 가능해집니다</li><li>설정 가이드는 커뮤니티에서 안내해드릴게요</li></ul><p><strong>이걸 하면 이런 변화가!</strong></p><blockquote><p>AI가 텍스트를 만들어주는 도구에서, 실제 업무를 처리하는 비서가 됩니다. &quot;이제 진짜 AI 비서가 생겼다&quot; 는 순간이 옵니다.</p></blockquote><hr><h2 id="🤝-혼자-하지-마세요" tabindex="-1">🤝 혼자 하지 마세요! <a class="header-anchor" href="#🤝-혼자-하지-마세요" aria-label="Permalink to &quot;🤝 혼자 하지 마세요!&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">커뮤니티가 있습니다</p><p>막히는 게 생기면 혼자 끙끙 앓지 마세요. 질문 하나가 몇 시간의 삽질을 아껴줍니다.</p><p>작은 것도, 이상한 것도, 다 괜찮습니다. 같이 배우는 분들이 있습니다.</p><ul><li>💬 <strong>오픈카톡</strong>: [세미나 참석자 전용 링크]</li><li>📸 <strong>최주원 인스타</strong>: <a href="https://instagram.com/ai_joowon" target="_blank" rel="noreferrer">@ai_joowon</a></li></ul></div><p>혼자 막히는 것보다 질문하는 게 훨씬 빠릅니다. &quot;이런 것도 물어봐도 되나?&quot; 싶은 것도 편하게 올려주세요. 기다리고 있을게요.</p><hr><h2 id="더-배우고-싶다면" tabindex="-1">더 배우고 싶다면 <a class="header-anchor" href="#더-배우고-싶다면" aria-label="Permalink to &quot;더 배우고 싶다면&quot;">​</a></h2><p>공식 문서는 영어지만, 필요한 부분은 Claude Code에게 번역 요청하면 됩니다.</p><ul><li>Claude Code 공식 문서: <a href="https://docs.anthropic.com/en/docs/claude-code" target="_blank" rel="noreferrer">https://docs.anthropic.com/en/docs/claude-code</a></li><li>Claude Code 시작하기: <a href="https://claude.ai/code" target="_blank" rel="noreferrer">https://claude.ai/code</a></li></ul><hr><h2 id="오늘이-시작입니다-🌱" tabindex="-1">오늘이 시작입니다 🌱 <a class="header-anchor" href="#오늘이-시작입니다-🌱" aria-label="Permalink to &quot;오늘이 시작입니다 🌱&quot;">​</a></h2><p>세미나에 참석해주셔서 진심으로 감사합니다.</p><p>AI를 잘 쓰는 건 코딩 실력이 아닙니다. <strong>&quot;무엇을 시킬지 아는 것&quot;</strong>, 그게 전부입니다.</p><p>오늘 여러분은 그 첫 걸음을 내디뎠습니다.</p><p>처음엔 어색하고, 가끔 잘 안 되고, &quot;내가 맞게 하고 있나?&quot; 싶은 순간도 올 겁니다. 그래도 괜찮습니다. 그게 배우는 과정입니다.</p><p>한 달 뒤에 돌아보면, 오늘이 달라지기 시작한 날이었다는 걸 알게 될 겁니다.</p><p>앞으로의 여정을 진심으로 응원합니다. 함께 가요. 💪</p><p>— 최주원 (AI JOOWON)</p>',47)])])}const q=a(r,[["render",i]]);export{h as __pageData,q as default};
